    { name: "碎牛肉饭(Picadillo)", cuisine: "哈瓦那", country: "古巴", city: "哈瓦那", note: "牛肉末炒番茄、橄榄、葡萄干，配白米和炸大蕉，是古巴家庭的日常一餐。", type: "其它", flavor: ["咸鲜", "甜"], spice: 0, diet: "荤", protein: ["牛", "面米"] }
